import{_ as o,o as s,c as a,ai as r}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"API Usage and Costs","description":"","frontmatter":{"summary":"Audit what can spend money, which keys are used, and how to view usage","read_when":["You want to understand which features may call paid APIs","You need to audit keys, costs, and usage visibility","You’re explaining /status or /usage cost reporting"],"title":"API Usage and Costs"},"headers":[],"relativePath":"reference/api-usage-costs.md","filePath":"reference/api-usage-costs.md","lastUpdated":null}'),t={name:"reference/api-usage-costs.md"};function i(n,e,d,c,l,h){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="api-usage-costs" tabindex="-1"><a class="header-anchor" href="#api-usage-costs">#</a> API usage &amp; costs</h1><p>This doc lists <strong>features that can invoke API keys</strong> and where their costs show up. It focuses on OpenSoul features that can generate provider usage or paid API calls.</p><h2 id="where-costs-show-up-chat-cli" tabindex="-1"><a class="header-anchor" href="#where-costs-show-up-chat-cli">#</a> Where costs show up (chat + CLI)</h2><p><strong>Per-session cost snapshot</strong></p><ul><li><code>/status</code> shows the current session model, context usage, and last response tokens.</li><li>If the model uses <strong>API-key auth</strong>, <code>/status</code> also shows <strong>estimated cost</strong> for the last reply.</li></ul><p><strong>Per-message cost footer</strong></p><ul><li><code>/usage full</code> appends a usage footer to every reply, including <strong>estimated cost</strong> (API-key only).</li><li><code>/usage tokens</code> shows tokens only; OAuth flows hide dollar cost.</li></ul><p><strong>CLI usage windows (provider quotas)</strong></p><ul><li><code>opensoul status --usage</code> and <code>opensoul channels list</code> show provider <strong>usage windows</strong> (quota snapshots, not per-message costs).</li></ul><p>See <a href="/docs/reference/token-use">Token use &amp; costs</a> for details and examples.</p><h2 id="how-keys-are-discovered" tabindex="-1"><a class="header-anchor" href="#how-keys-are-discovered">#</a> How keys are discovered</h2><p>OpenSoul can pick up credentials from:</p><ul><li><strong>Auth profiles</strong> (per-agent, stored in <code>auth-profiles.json</code>).</li><li><strong>Environment variables</strong> (e.g. <code>OPENAI_API_KEY</code>, <code>BRAVE_API_KEY</code>, <code>FIRECRAWL_API_KEY</code>).</li><li><strong>Config</strong> (<code>models.providers.*.apiKey</code>, <code>tools.web.search.*</code>, <code>tools.web.fetch.firecrawl.*</code>, <code>memorySearch.*</code>, <code>talk.apiKey</code>).</li><li><strong>Skills</strong> (<code>skills.entries.&lt;name&gt;.apiKey</code>) which may export keys to the skill process env.</li></ul><h2 id="features-that-can-spend-keys" tabindex="-1"><a class="header-anchor" href="#features-that-can-spend-keys">#</a> Features that can spend keys</h2><h3 id="_1-core-model-responses-chat-tools" tabindex="-1"><a class="header-anchor" href="#_1-core-model-responses-chat-tools">#</a> 1) Core model responses (chat + tools)</h3><p>Every reply or tool call uses the <strong>current model provider</strong> (OpenAI, Anthropic, etc). This is the primary source of usage and cost.</p><p>See <a href="/docs/providers/models">Models</a> for pricing config and <a href="/docs/reference/token-use">Token use &amp; costs</a> for display.</p><h3 id="_2-media-understanding-audio-image-video" tabindex="-1"><a class="header-anchor" href="#_2-media-understanding-audio-image-video">#</a> 2) Media understanding (audio/image/video)</h3><p>Inbound media can be summarized/transcribed before the reply runs. This uses model/provider APIs.</p><ul><li>Audio: OpenAI / Groq / Deepgram (now <strong>auto-enabled</strong> when keys exist).</li><li>Image: OpenAI / Anthropic / Google.</li><li>Video: Google.</li></ul><p>See <a href="/docs/nodes/media-understanding">Media understanding</a>.</p><h3 id="_3-memory-embeddings-semantic-search" tabindex="-1"><a class="header-anchor" href="#_3-memory-embeddings-semantic-search">#</a> 3) Memory embeddings + semantic search</h3><p>Semantic memory search uses <strong>embedding APIs</strong> when configured for remote providers:</p><ul><li><code>memorySearch.provider = &quot;openai&quot;</code> → OpenAI embeddings</li><li><code>memorySearch.provider = &quot;gemini&quot;</code> → Gemini embeddings</li><li><code>memorySearch.provider = &quot;voyage&quot;</code> → Voyage embeddings</li><li>Optional fallback to a remote provider if local embeddings fail</li></ul><p>You can keep it local with <code>memorySearch.provider = &quot;local&quot;</code> (no API usage).</p><p>See <a href="/docs/concepts/memory">Memory</a>.</p><h3 id="_4-web-search-tool-brave-perplexity-via-openrouter" tabindex="-1"><a class="header-anchor" href="#_4-web-search-tool-brave-perplexity-via-openrouter">#</a> 4) Web search tool (Brave / Perplexity via OpenRouter)</h3><p><code>web_search</code> uses API keys and may incur usage charges:</p><ul><li><strong>Brave Search API</strong>: <code>BRAVE_API_KEY</code> or <code>tools.web.search.apiKey</code></li><li><strong>Perplexity</strong> (via OpenRouter): <code>PERPLEXITY_API_KEY</code> or <code>OPENROUTER_API_KEY</code></li></ul><p><strong>Brave free tier (generous):</strong></p><ul><li><strong>2,000 requests/month</strong></li><li><strong>1 request/second</strong></li><li><strong>Credit card required</strong> for verification (no charge unless you upgrade)</li></ul><p>See <a href="/docs/tools/web">Web tools</a>.</p><h3 id="_5-web-fetch-tool-firecrawl" tabindex="-1"><a class="header-anchor" href="#_5-web-fetch-tool-firecrawl">#</a> 5) Web fetch tool (Firecrawl)</h3><p><code>web_fetch</code> can call <strong>Firecrawl</strong> when an API key is present:</p><ul><li><code>FIRECRAWL_API_KEY</code> or <code>tools.web.fetch.firecrawl.apiKey</code></li></ul><p>If Firecrawl isn’t configured, the tool falls back to direct fetch + readability (no paid API).</p><p>See <a href="/docs/tools/web">Web tools</a>.</p><h3 id="_6-provider-usage-snapshots-status-health" tabindex="-1"><a class="header-anchor" href="#_6-provider-usage-snapshots-status-health">#</a> 6) Provider usage snapshots (status/health)</h3><p>Some status commands call <strong>provider usage endpoints</strong> to display quota windows or auth health. These are typically low-volume calls but still hit provider APIs:</p><ul><li><code>opensoul status --usage</code></li><li><code>opensoul models status --json</code></li></ul><p>See <a href="/docs/cli/models">Models CLI</a>.</p><h3 id="_7-compaction-safeguard-summarization" tabindex="-1"><a class="header-anchor" href="#_7-compaction-safeguard-summarization">#</a> 7) Compaction safeguard summarization</h3><p>The compaction safeguard can summarize session history using the <strong>current model</strong>, which invokes provider APIs when it runs.</p><p>See <a href="/docs/reference/session-management-compaction">Session management + compaction</a>.</p><h3 id="_8-model-scan-probe" tabindex="-1"><a class="header-anchor" href="#_8-model-scan-probe">#</a> 8) Model scan / probe</h3><p><code>opensoul models scan</code> can probe OpenRouter models and uses <code>OPENROUTER_API_KEY</code> when probing is enabled.</p><p>See <a href="/docs/cli/models">Models CLI</a>.</p><h3 id="_9-talk-speech" tabindex="-1"><a class="header-anchor" href="#_9-talk-speech">#</a> 9) Talk (speech)</h3><p>Talk mode can invoke <strong>ElevenLabs</strong> when configured:</p><ul><li><code>ELEVENLABS_API_KEY</code> or <code>talk.apiKey</code></li></ul><p>See <a href="/docs/nodes/talk">Talk mode</a>.</p><h3 id="_10-skills-third-party-apis" tabindex="-1"><a class="header-anchor" href="#_10-skills-third-party-apis">#</a> 10) Skills (third-party APIs)</h3><p>Skills can store <code>apiKey</code> in <code>skills.entries.&lt;name&gt;.apiKey</code>. If a skill uses that key for external APIs, it can incur costs according to the skill’s provider.</p><p>See <a href="/docs/tools/skills">Skills</a>.</p>',54)])])}const g=o(t,[["render",i]]);export{u as __pageData,g as default};
